#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define ETA 0.3f
#define MOMENTUM 0.3f
#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16

__kernel void bpnn_layerforward_ocl(__global float* input_units,
                                   __global float* hidden_units,
                                   __global float* input_weights,
                                   __global float* hidden_partial_sum,
                                   __local float* lsum,
                                   __local float* lweights,
                                   const int input_n,
                                   const int hidden_n)
{
    int tx = get_local_id(0);
    int ty = get_local_id(1);
    int bx = get_group_id(0);
    int by = get_group_id(1);

    int row = bx * BLOCK_SIZE + tx; // input index
    int col = by * BLOCK_SIZE + ty; // hidden index

    int input_size = input_n + 1;
    int hidden_size = hidden_n + 1;

    // Each work-item computes partial sum for one element of the output matrix block
    float sum = 0.0f;

    // Load input units and weights into local memory
    if (row < input_size && ty < BLOCK_SIZE && col < hidden_size) {
        lweights[ty * BLOCK_SIZE + tx] = input_weights[row * hidden_size + col];
    } else {
        lweights[ty * BLOCK_SIZE + tx] = 0.0f;
    }

    if (col < hidden_size && tx < BLOCK_SIZE) {
        lsum[tx * BLOCK_SIZE + ty] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute partial sum for this block
    for (int i = 0; i < BLOCK_SIZE; i++) {
        int idx = bx * BLOCK_SIZE + i;
        if (idx < input_size && col < hidden_size) {
            float w = lweights[i * BLOCK_SIZE + ty];
            float inp = (idx < input_size) ? input_units[idx] : 0.0f;
            sum += w * inp;
        }
    }

    // Store partial sum in local memory
    lsum[tx * BLOCK_SIZE + ty] = sum;

    barrier(CLK_LOCAL_MEM_FENCE);

    // Reduce partial sums along the x dimension
    if (ty == 0 && col < hidden_size) {
        float total = 0.0f;
        for (int i = 0; i < BLOCK_SIZE; i++) {
            total += lsum[i * BLOCK_SIZE + tx];
        }
        int idx = by * BLOCK_SIZE + tx;
        if (idx > 0 && idx < hidden_size) {
            hidden_units[idx] = 1.0f / (1.0f + exp(-total));
        }
        if (idx == 0) {
            hidden_units[0] = 1.0f;
        }
    }
}

__kernel void bpnn_adjust_weights_ocl(__global float* delta,
                                     const int ndelta,
                                     __global float* ly,
                                     const int nly,
                                     __global float* w,
                                     __global float* oldw)
{
    int j = get_global_id(0) + 1; // delta index
    int k = get_global_id(1);     // ly index

    if (j <= ndelta && k <= nly) {
        int idx = k * (ndelta + 1) + j;
        float new_dw = ETA * delta[j] * ly[k] + MOMENTUM * oldw[idx];
        w[idx] += new_dw;
        oldw[idx] = new_dw;
    }
}
